@startuml
skinparam classAttributeIconSize 0

class User {
    -id: integer
    -name: string
    +getId(): integer
    +getName(): string
}

class Employee {
    -position: string
    +getPosition(): string
}

class Owner {
    -balance: integer
    +getBalance(): integer
}

interface StoreInterface {
    +getStoreName(): string
    +getOwnerName(): string
    +getEmployees(): []Employee
}

class CakeStore {
    -storeName: string
    -owner: Owner
    -employees: []Employee
}

class CoffeeStore {
    -storeName: string
    -owner: Owner
    -employees: []Employee
}

class MainStore {
    +storeInterface: StoreInterface
}

User <|-- Employee : extends
User <|-- Owner : extends
CakeStore --|> StoreInterface : implements
CoffeeStore ..|> StoreInterface : implements
MainStore --> StoreInterface : uses
Employee o-- CakeStore : has many employees
Employee o-- CoffeeStore : has many employees
Owner *-- CakeStore : owns store
Owner *-- CoffeeStore : owns store
@enduml
